BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqName ?analysisName ?analysisType WHERE {
  ?req rdf:type ?reqType .
  ?req vocab:NamedElement_name ?reqName .
  FILTER(
    CONTAINS(LCASE(STR(?reqName)), LCASE("peak%20power%20limit%20requirement"))
    || (CONTAINS(LCASE(STR(?reqName)), LCASE("power%20limit")) && CONTAINS(LCASE(STR(?reqName)), LCASE("peak")))
    || CONTAINS(LCASE(STR(?reqName)), LCASE("peak%20power%20limit%20requirement%20tmt"))
    || CONTAINS(LCASE(STR(?reqName)), LCASE("powerPeakLimit"))
  )

  ?analysis rdf:type ?analysisType .
  ?analysis vocab:NamedElement_name ?analysisName .
  FILTER(
    CONTAINS(LCASE(STR(?analysisName)), LCASE("standby"))
    || CONTAINS(LCASE(STR(?analysisName)), LCASE("online"))
  )

  {
    ?analysis vocab:satisfy+ ?req .
  }
  UNION
  {
    ?analysis vocab:dependency+ ?req .
  }
  UNION
  {
    ?analysis vocab:Dependency_supplier+ ?req .
  }
  UNION
  {
    ?analysis vocab:Element__relationshipOfRelatedElement ?req .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?instName ?constraintName ?scenarioName WHERE {
  ?inst rdf:type vocab:instance%20specification .
  ?inst vocab:NamedElement_name ?instName .
  FILTER(
    (CONTAINS(LCASE(STR(?instName)), LCASE("satisfy%20peak%20power")) || CONTAINS(LCASE(STR(?instName)), LCASE("satisfy%20peak%20power%20explanation")))
    && (CONTAINS(LCASE(STR(?instName)), LCASE("standby")) || CONTAINS(LCASE(STR(?instName)), LCASE("online")))
    || CONTAINS(LCASE(STR(?instName)), LCASE("peak%20power%20limit%20requirement"))
  )

  OPTIONAL {
    ?constraint rdf:type vocab:constraint%20block .
    ?constraint vocab:NamedElement_name ?constraintName .
    FILTER(CONTAINS(LCASE(STR(?constraintName)), LCASE("peak%20power")))
  }

  OPTIONAL {
    ?scen rdf:type vocab:block .
    ?scen vocab:NamedElement_name ?scenarioName .
    FILTER(
      CONTAINS(LCASE(STR(?scenarioName)), LCASE("standby"))
      || CONTAINS(LCASE(STR(?scenarioName)), LCASE("online"))
    )
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT
  ?paramName
  ?constraintName
  ?valName
  ?scenarioName
WHERE {
  ?param rdf:type vocab:constraint%20parameter .
  ?param vocab:NamedElement_name ?paramName .
  FILTER(CONTAINS(LCASE(STR(?paramName)), LCASE("requiredpeaklimitload")))

  OPTIONAL {
    ?constraint vocab:Element_ownedElement+ ?param .
    ?constraint rdf:type vocab:constraint%20block .
    ?constraint vocab:NamedElement_name ?constraintName .
  }

  OPTIONAL {
    ?param vocab:Element_ownedElement+ ?valElem .
    ?valElem vocab:NamedElement_name ?valName .
  }

  # Try to find scenario blocks by linking via analysis/instance names that include standby/online
  OPTIONAL {
    ?inst rdf:type vocab:instance%20specification .
    ?inst vocab:NamedElement_name ?instName .
    FILTER(
      CONTAINS(LCASE(STR(?instName)), LCASE("satisfy%20peak%20power%20explanation"))
      && (CONTAINS(LCASE(STR(?instName)), LCASE("standby")) || CONTAINS(LCASE(STR(?instName)), LCASE("online")))
    )

    OPTIONAL {
      ?inst vocab:Element_owner ?scenario .
      ?scenario vocab:NamedElement_name ?scenarioName .
      FILTER(
        CONTAINS(LCASE(STR(?scenarioName)), LCASE("standby"))
        || CONTAINS(LCASE(STR(?scenarioName)), LCASE("online"))
      )
    }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT
  ?slotOrVal
  ?slotName
  ?litType
  ?litValue
  ?scenarioName
WHERE {
  ?param rdf:type vocab:constraint%20parameter .
  ?param vocab:NamedElement_name "requiredPeakLimitLoad" .

  # Try to follow from parameter to a value/slot it references
  OPTIONAL { ?param vocab:InstanceSpecification_slot ?slotOrVal . }
  OPTIONAL { ?param vocab:slot ?slotOrVal . }
  OPTIONAL {
    ?param vocab:Element_ownedElement+ ?slotOrVal .
  }

  OPTIONAL {
    ?slotOrVal vocab:NamedElement_name ?slotName .
  }

  # Literal value cases
  OPTIONAL {
    ?lit rdf:type ?litType .
    FILTER(?litType IN (vocab:literal%20integer, vocab:literal%20real))
    ?slotOrVal vocab:Element_ownedElement+ ?lit .
    ?lit vocab:NamedElement_name ?litValueName .
  }

  OPTIONAL {
    ?lit rdf:type ?litType .
    FILTER(?litType IN (vocab:literal%20integer, vocab:literal%20real))
    ?lit vocab:value ?litValue .
    # connect slotOrVal to literal through owned elements
    ?slotOrVal vocab:Element_ownedElement+ ?lit .
  }

  # Scenario linkage heuristic: find related instance specifications tied to standby/online
  OPTIONAL {
    ?slotOrVal rdf:type vocab:instance%20specification .
    ?slotOrVal vocab:NamedElement_name ?scenarioName .
    FILTER(CONTAINS(LCASE(STR(?scenarioName)), LCASE("standby")) || CONTAINS(LCASE(STR(?scenarioName)), LCASE("online")))
  }
}
LIMIT 25
